-- 전국 반려견 동반 산책 장소 기본 데이터
-- user_id = 1 (관리자 계정 기준)

INSERT INTO places (user_id, title, content, latitude, longitude, category, status, rejection_reason, large_dog_available, parking_available, off_leash_available, like_count, admin_yn, deleted_at, created_date, updated_date) VALUES

-- ===================== 서울 =====================
(1, '월드컵공원 반려견 놀이터', '상암동 월드컵공원 내 반려견 전용 놀이터. 대형 운동장과 소형견 구역이 분리되어 있어 안전하게 이용 가능. 물놀이 시설도 있음.', 37.5685, 126.8920, 'PARK', 'APPROVED', NULL, true, true, true, 0, 'Y', NULL, NOW(), NOW()),
(1, '보라매공원 반려견 놀이터', '동작구 보라매공원 내 반려견 전용 놀이터. 넓은 잔디 구역과 어질리티 시설 구비. 주변 산책로도 잘 정비되어 있음.', 37.4923, 126.9219, 'PARK', 'APPROVED', NULL, true, true, true, 0, 'Y', NULL, NOW(), NOW()),
(1, '서울숲 반려견 산책로', '성동구 서울숲. 한강변을 따라 조성된 넓은 공원. 반려견과 산책하기 좋은 코스가 다양하게 있으며 계절별 풍경이 아름다움.', 37.5444, 127.0374, 'PARK', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '올림픽공원 반려견 산책로', '송파구 올림픽공원. 9경(景)을 따라 걷는 코스가 인기. 넓고 잘 정비된 산책로와 공원 내 잔디 광장 이용 가능.', 37.5219, 127.1219, 'PARK', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '북서울꿈의숲 반려견 산책', '강북구 번동 북서울꿈의숲. 대규모 근린공원으로 오르막 산책로부터 평지 코스까지 다양. 창포원과 월영지 주변 코스 추천.', 37.6264, 127.0459, 'PARK', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '한강공원 반포지구 반려견 산책', '서초구 반포 한강공원. 세빛섬과 달빛광장 주변 산책로. 야경이 아름답고 넓은 잔디 광장이 있어 반려견과 뛰놀기 좋음.', 37.5130, 126.9948, 'PARK', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '광나루 한강공원 반려견 산책', '광진구 광장동 광나루 한강공원. 광활한 잔디밭과 강변 산책로. 조용하고 한적해서 반려견과 느긋하게 산책하기 좋음.', 37.5433, 127.1262, 'PARK', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '하늘공원 억새 산책로', '마포구 상암동 하늘공원. 억새로 유명한 공원으로 정상에서 서울 전경이 한눈에 보임. 반려견과 함께 오르는 계단 코스 인기.', 37.5712, 126.8849, 'TRAIL', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),

-- ===================== 경기도 =====================
(1, '서울대공원 산책로', '과천시 서울대공원. 청계산 자락을 따라 조성된 넓은 공원. 반려견 동반 가능 구역이 넓고 자연 속 산책 가능. 주말에는 혼잡할 수 있음.', 37.4356, 127.0022, 'PARK', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '광교호수공원 반려견 놀이터', '수원시 영통구 광교호수공원. 대규모 호수 공원으로 산책로가 잘 정비되어 있음. 반려견 전용 놀이터 구비. 대형견도 자유롭게 이용 가능.', 37.2877, 127.0491, 'PARK', 'APPROVED', NULL, true, true, true, 0, 'Y', NULL, NOW(), NOW()),
(1, '기흥호수공원 반려견 놀이터', '용인시 기흥구 기흥호수공원. 호수 둘레를 따라 산책로 조성. 반려견 전용 놀이터 내 오프리쉬 가능. 물가에서 물놀이하는 강아지들이 많음.', 37.2283, 127.1030, 'PARK', 'APPROVED', NULL, true, true, true, 0, 'Y', NULL, NOW(), NOW()),
(1, '마장호수 출렁다리 산책로', '파주시 광탄면 마장호수. 국내 최장 보행 현수교(220m) 출렁다리가 있는 호수 산책로. 호수를 한 바퀴 도는 코스(약 5km)가 인기.', 37.8447, 126.7356, 'TRAIL', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '운정호수공원 반려견 산책', '파주시 운정신도시 운정호수공원. 도심 속 호수 공원으로 잘 정비된 산책로. 반려견과 함께하는 시민들이 많아 반려견 친화적인 분위기.', 37.7282, 126.7660, 'PARK', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '일산호수공원 반려견 산책로', '고양시 일산동구 일산호수공원. 국내 최대 인공호수 공원 중 하나. 넓은 잔디 광장과 호수 둘레길이 아름다움. 꽃이 피는 계절에 특히 인기.', 37.6765, 126.7709, 'PARK', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '왕숙천 둔치 산책로', '남양주시 왕숙천 둔치. 천변을 따라 이어진 넓은 산책로. 풀밭에서 뛰어노는 반려견들을 자주 볼 수 있으며 한적하고 자연스러운 분위기.', 37.6527, 127.1896, 'TRAIL', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '태화산 자연휴양림 산책로', '양평군 용문면 태화산 일대. 숲속 피톤치드 가득한 산책로. 반려견과 함께 자연 속 트레킹 가능. 계곡물에서 물놀이하기 좋은 계절형 코스.', 37.5478, 127.4923, 'TRAIL', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),

-- ===================== 인천 =====================
(1, '인천대공원 반려동물 놀이터', '남동구 장수동 인천대공원. 3,524㎡ 규모의 반려동물 전용 놀이터. 대형견과 소형견 구역 분리 운영. 각종 운동 기구와 음수대 구비.', 37.4108, 126.7393, 'PARK', 'APPROVED', NULL, true, true, true, 0, 'Y', NULL, NOW(), NOW()),
(1, '을왕리해수욕장 반려견 산책', '인천 중구 을왕동 을왕리해수욕장. 해변 산책이 가능한 반려견 동반 허용 구역. 모래사장에서 뛰어노는 반려견들이 많음. 일몰 풍경이 아름다움.', 37.4504, 126.3729, 'TRAIL', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '청라호수공원 반려견 산책로', '인천 서구 청라동 청라호수공원. 워터프런트 중심 도시 공원. 호수 둘레를 따라 조성된 산책로가 잘 정비되어 있어 반려견 산책에 최적.', 37.5381, 126.6379, 'PARK', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),

-- ===================== 부산 =====================
(1, '이기대 해안산책로', '부산 남구 용호동 이기대 도시자연공원. 해안 절벽을 따라 이어지는 약 4.7km 산책로. 바다 경치가 절경이며 반려견 동반 가능. 체력 소모가 상당함.', 35.1028, 129.1267, 'TRAIL', 'APPROVED', NULL, true, false, false, 0, 'Y', NULL, NOW(), NOW()),
(1, 'APEC나루공원 반려견 산책', '부산 해운대구 우동 APEC나루공원. 수영강변을 따라 조성된 도심 공원. 잘 정비된 산책로와 잔디 광장. 해운대 도심에서 접근성이 좋음.', 35.1731, 129.1309, 'PARK', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '해운대 달맞이길 산책로', '부산 해운대구 중동 달맞이길. 해운대해수욕장 북쪽 언덕을 따라 이어지는 아름다운 산책로. 소나무 숲 사이로 바다 전망을 즐길 수 있음.', 35.1584, 129.1622, 'TRAIL', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '광안리해수욕장 해변 산책로', '부산 수영구 광안동 광안리해수욕장. 해변을 따라 산책 가능. 광안대교 야경이 아름다워 저녁 산책 명소. 비교적 반려견 친화적인 분위기.', 35.1531, 129.1184, 'TRAIL', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '삼락공원 반려견 놀이터', '부산 사상구 삼락동 삼락생태공원. 낙동강변에 위치한 대규모 생태공원. 반려견 전용 놀이터 운영. 넓은 잔디밭에서 자유롭게 뛰어놀 수 있음.', 35.1754, 128.9869, 'PARK', 'APPROVED', NULL, true, true, true, 0, 'Y', NULL, NOW(), NOW()),
(1, '낙동강 둔치 자전거도로 산책', '부산 강서구 낙동강 둔치. 강변을 따라 길게 이어진 평지 산책로. 자전거 도로와 분리된 보행로 있음. 철새 도래지 주변 자연 경관이 수려함.', 35.1674, 128.9647, 'TRAIL', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),

-- ===================== 대전 =====================
(1, '대전 반려동물 공원', '대전 서구 금고동 대전반려동물공원. 반려견 전용으로 조성된 공원. 대형견과 소형견 놀이터 분리. 음수대, 배변 처리 시설, 휴식 공간 완비.', 36.3485, 127.3241, 'PARK', 'APPROVED', NULL, true, true, true, 0, 'Y', NULL, NOW(), NOW()),
(1, '갑천 자연형 하천 산책로', '대전 유성구 갑천 둔치. 자연형 하천 둔치를 따라 이어진 산책로. 도심 속 자연 환경이 잘 보존되어 있으며 계절별로 다른 풍경을 즐길 수 있음.', 36.3736, 127.3509, 'TRAIL', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),

-- ===================== 광주 =====================
(1, '광주 중앙공원 반려견 산책로', '광주 동구 중앙공원 및 주변 산책로. 도심 속 녹지 공간으로 반려견과 함께 산책하기 좋음. 시내 접근성이 좋아 평일에도 이용객이 많음.', 35.1468, 126.9165, 'PARK', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '무등산 증심사 계곡 산책로', '광주 동구 증심사 방면 무등산 초입 산책로. 계곡을 따라 이어진 자연 산책로. 여름에 시원하고 반려견과 계곡 물놀이 가능. 오르막 없이 평탄한 초반 구간 인기.', 35.1358, 126.9893, 'TRAIL', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),

-- ===================== 대구 =====================
(1, '수성못 반려견 산책로', '대구 수성구 수성동 수성못. 도심 호수 주변 산책로. 벚꽃 시즌에 특히 아름답고 반려견과 함께 호수 둘레를 산책하는 시민들이 많음.', 35.8508, 128.6233, 'PARK', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '달성공원 주변 산책로', '대구 중구 달성동 달성공원 주변. 오래된 도심 공원으로 반려견과 함께 산책 가능. 성벽 둘레를 따라 걷는 코스가 인기.', 35.8707, 128.5820, 'PARK', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),

-- ===================== 울산 =====================
(1, '울산 반려견 전용 공원', '울산 울주군 청량면 반려견 전용 공원. 전국 최초 반려견 전용 운동시설. 수영장, 장애물 경기장, 운동 기구 완비. 대형견 전용 구역과 소형견 구역 분리 운영.', 35.4882, 129.2197, 'PARK', 'APPROVED', NULL, true, true, true, 0, 'Y', NULL, NOW(), NOW()),
(1, '태화강 국가정원 산책로', '울산 중구 태화동 태화강 국가정원. 십리대숲(대나무숲)으로 유명한 국가정원. 강변을 따라 이어진 넓은 산책로. 반려견과 함께 대나무숲 산책이 인기.', 35.5429, 129.3157, 'PARK', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),

-- ===================== 강원도 =====================
(1, '멍비치 애견전용해수욕장', '강원 양양군 손양면 지경리해수욕장 내 멍비치. 국내 애견 전용 해수욕장. 모래사장에서 목줄 없이 마음껏 뛰어놀 수 있음. 여름 성수기에 특히 인기.', 38.0977, 128.6262, 'PARK', 'APPROVED', NULL, true, true, true, 0, 'Y', NULL, NOW(), NOW()),
(1, '설악해맞이공원 반려견 산책', '강원 속초시 조양동 설악해맞이공원. 동해 바다를 바라보며 산책 가능. 설악산 배경의 아름다운 풍경. 반려견과 함께하기 좋은 해안 공원.', 38.2049, 128.5945, 'PARK', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '낙산해수욕장 반려견 산책로', '강원 양양군 강현면 낙산해수욕장. 동해 해변 산책로. 낙산사 인근의 소나무숲과 해변이 어우러져 아름다운 풍경. 아침 산책 명소로 유명.', 38.0773, 128.6310, 'TRAIL', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '횡성호수길 반려견 트레킹', '강원 횡성군 횡성호수 둘레길. 잔잔한 호수를 따라 이어진 약 16km 둘레길. 반려견과 함께 전 구간 또는 일부 구간 트레킹 가능. 자연 경관이 수려함.', 37.4933, 127.9879, 'TRAIL', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '춘천 의암호 스카이워크 산책로', '강원 춘천시 근화동 의암호 스카이워크 인근. 호수를 내려다보며 걷는 유리 전망대와 연결된 산책로. 반려견과 함께 호수 뷰를 즐기며 걷기 좋음.', 37.8813, 127.7225, 'TRAIL', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),

-- ===================== 충청도 =====================
(1, '청주 미호천 생태 산책로', '충북 청주시 흥덕구 미호천 둔치. 자연 생태 하천을 따라 이어진 산책로. 넓은 잔디 둔치에서 반려견이 마음껏 뛰어놀 수 있음. 조류 관찰도 가능.', 36.6227, 127.4417, 'TRAIL', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '천안 성정공원 반려견 산책로', '충남 천안시 서북구 성정동 성정공원. 도심 속 공원으로 반려견 산책로 잘 정비. 그늘이 있는 나무 아래 산책로가 특히 인기. 음수대 구비.', 36.8303, 127.1494, 'PARK', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),

-- ===================== 경상도 =====================
(1, '경주 화랑의 언덕 반려견 산책', '경북 경주시 화랑의 언덕. 신라 역사 문화 경관과 함께하는 산책로. 잘 조성된 공원 내 산책로에서 반려견과 함께 역사 유적지 주변을 산책 가능.', 35.8562, 129.2249, 'PARK', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '남해 독일마을 반려견 산책', '경남 남해군 삼동면 독일마을. 남해 바다 전망의 유럽풍 마을. 마을 내 산책로와 해안 산책이 가능하며 반려견과 함께하기 좋은 관광지.', 34.8397, 128.0532, 'ETC', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '함양 상림공원 반려견 산책로', '경남 함양군 함양읍 상림공원. 천연기념물 제154호로 지정된 우리나라 최고(最古)의 인공 숲. 넓은 숲속 산책로에서 반려견과 함께 자연을 즐길 수 있음.', 35.5195, 127.7258, 'PARK', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '창원 주남저수지 탐방로', '경남 창원시 의창구 동읍 주남저수지. 철새 도래지로 유명한 저수지 둘레 탐방로. 자연 생태 환경 속에서 반려견과 함께 산책 가능. 철새 관찰 계절에 특히 인기.', 35.3133, 128.6386, 'TRAIL', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),

-- ===================== 전라도 =====================
(1, '군산 은파호수공원 반려견 산책', '전북 군산시 나운동 은파호수공원. 넓은 호수 주변을 따라 산책로 조성. 물빛 다리가 명소이며 반려견과 함께 호수 둘레길을 걷기 좋음.', 35.9888, 126.7153, 'PARK', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '순천만 국가정원 반려견 산책', '전남 순천시 오천동 순천만국가정원. 세계 5대 연안습지인 순천만 인근 국가정원. 광활한 갈대밭과 정원을 반려견과 함께 거닐 수 있음. 가을 억새 시즌 인기.', 34.9333, 127.5022, 'PARK', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '담양 메타세쿼이아 가로수길', '전남 담양군 담양읍 메타세쿼이아 가로수길. 영화 속 한 장면 같은 가로수길. 반려견과 함께 걷기 좋은 약 8.5km 구간. 사계절 모두 아름다운 산책 명소.', 35.3224, 126.9876, 'TRAIL', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),

-- ===================== 제주도 =====================
(1, '제주 협재해수욕장 반려견 산책', '제주시 한림읍 협재해수욕장. 에메랄드빛 바다와 하얀 모래사장이 아름다운 해변. 반려견과 함께 해변 산책 가능. 비양도 전망과 함께하는 산책 코스 인기.', 33.3942, 126.2389, 'TRAIL', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '제주 한라수목원 반려견 산책로', '제주시 연동 한라수목원. 한라산 중턱에 위치한 수목원. 다양한 식물과 함께하는 숲속 산책. 반려견과 함께 피톤치드 가득한 숲길을 거닐 수 있음.', 33.4826, 126.5054, 'PARK', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '제주 환상숲 곶자왈 산책로', '제주시 한경면 저지리 환상숲 곶자왈. 제주 특유의 화산 지형 위에 형성된 원시 숲. 반려견과 함께 독특한 제주 생태계를 체험할 수 있는 산책로.', 33.3359, 126.2197, 'TRAIL', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '제주 성산일출봉 광치기해변 산책로', '서귀포시 성산읍 광치기해변. 성산일출봉을 배경으로 한 해변 산책로. 일출 시간에 반려견과 함께 걷는 코스로 인기. 현무암 지형이 독특하고 아름다움.', 33.4586, 126.9392, 'TRAIL', 'APPROVED', NULL, true, true, false, 0, 'Y', NULL, NOW(), NOW()),
(1, '제주 올레 7코스 반려견 산책', '서귀포시 법환동~월평동 올레 7코스 일부. 제주 해안을 따라 걷는 올레길 중 반려견 동반이 용이한 구간. 외돌개와 월평 포구를 잇는 아름다운 해안 산책로.', 33.2409, 126.5087, 'TRAIL', 'APPROVED', NULL, true, false, false, 0, 'Y', NULL, NOW(), NOW());
